const aiData = items[0].json;

// Remove markdown formatting from output string
let outputString = aiData.output.toString();
outputString = outputString.replace(/^```json\s*/, '').replace(/\s*```$/, '').replace(/\n/g, '');

// Parse the JSON
const parsedAI = JSON.parse(outputString);

// Get classifier data
const classifierData = $('Code in JavaScript').first().json;

// Clean sender info
const senderName = (classifierData.sender_name || '').replace(/^From:\s*/, '').trim();
const senderEmail = classifierData.sender_email || 'Unknown';
const subject = (classifierData.subject || '').replace(/^Subject:\s*/, '').trim();

// Map classifications
const classificationMap = {
  'red_urgent': 'Urgent',
  'blue_info': 'Information',
  'grey_ignore': 'Promotional'
};

const classification = parsedAI.classification || 'grey_ignore';
const mappedCategory = classificationMap[classification] || 'Promotional';

// Build final result
const result = {
  json: {
    id: `card_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
    sender_name: senderName,
    sender_email: senderEmail,
    subject: subject,
    category: mappedCategory,
    next_action: parsedAI.next_action || null,
    deadline: parsedAI.extracted_deadline || null,
    ai_draft: parsedAI.draft_response || null,
    summary_bullets: Array.isArray(parsedAI.summary_bullets) ? parsedAI.summary_bullets.join(' | ') : null,
    read_time: parsedAI.read_time || null,
    board_section: 'todo',
    created_at: new Date().toISOString(),
    updated_at: new Date().toISOString()
  }
};

return result;

const email = items[0].json;

let senderName = '';
let senderEmail = '';

// Gmail sends 'from' as an object with .text property
const fromData = email.headers?.from;

if (typeof fromData === 'object' && fromData?.text) {
  // Use the .text property which has proper format: "Name" <email@example.com>
  const fromMatch = fromData.text.match(/([^<]*)<([^>]*)>/);

  if (fromMatch) {
    senderName = fromMatch[1].trim().replace(/^"(.*)"$/, '$1') || fromData.name || '';
    senderEmail = fromMatch[2].trim();
  } else {
    // Fallback: use the name property
    senderName = fromData.name || 'Unknown';
    senderEmail = fromData.text || 'unknown@example.com';
  }
} else if (typeof fromData === 'string') {
  // Fallback for string format
  const fromMatch = fromData.match(/([^<]*)<([^>]*)>/);
  if (fromMatch) {
    senderName = fromMatch[1].trim();
    senderEmail = fromMatch[2].trim();
  } else {
    senderEmail = fromData.trim();
    senderName = senderEmail.split('@')[0];
  }
}

// Remove "From: " prefix if present
senderName = senderName.replace(/^From:\s*/, '').trim();

// Get email body
let emailBody = '';
if (email.bodyPlain) {
  emailBody = email.bodyPlain;
} else if (email.bodyHtml) {
  emailBody = email.bodyHtml.replace(/<[^>]*>/g, '').trim();
} else if (email.body) {
  emailBody = typeof email.body === 'object' ? (email.body.plain || email.body.html || '') : email.body;
} else if (email.text) {
  emailBody = email.text;
}

// Clean up body
emailBody = (emailBody || '')
  .trim()
  .slice(0, 2000)
  .replace(/\n\n+/g, '\n');

// Get subject - Remove "Subject: " prefix if present
let subject = email.headers?.subject || email.subject || '(No Subject)';
subject = subject.replace(/^Subject:\s*/, '').trim();

// Handle encoded subject (UTF-8 Base64)
if (subject.includes('=?UTF-8?B?')) {
  try {
    const parts = subject.match(/=\?UTF-8\?B\?([^?]+)\?=/g);
    if (parts) {
      parts.forEach(part => {
        const base64 = part.replace(/=\?UTF-8\?B\?|\?=/g, '');
        const decoded = Buffer.from(base64, 'base64').toString('utf-8');
        subject = subject.replace(part, decoded);
      });
      subject = subject.replace(/\s+/g, ' ').trim();
    }
  } catch (e) {
    console.log('Could not decode subject, using as-is:', subject);
  }
}

// Get message ID
const messageId = email.id || email.messageId || '';

// Get date - Remove "Date: " prefix if present
let date = email.headers?.date || email.date || new Date().toISOString();
date = date.replace(/^Date:\s*/, '').trim();

return {
  json: {
    id: messageId,
    messageId: messageId,
    sender_name: senderName || 'Unknown',
    sender_email: senderEmail || 'unknown@example.com',
    subject: subject,
    body: emailBody,
    date: date,
  }
};
